import { Client } from '@larksuiteoapi/node-sdk';

const client = new Client({
  appId: process.env.FEISHU_APP_ID,
  appSecret: process.env.FEISHU_APP_SECRET,
});

export default client;

import client from './client.js';

/**
 * 发送文本消息到飞书群或用户
 * @param {string} receiveId - 接收者 ID（群 chat_id 或用户 open_id）
 * @param {string} content - 消息内容（JSON 格式的飞书消息体）
 * @returns {Promise<object>} 发送结果
 */
export async function sendMessage(receiveId, content) {
  return client.im.message.create({
    params: { receive_id_type: 'chat_id' },
    data: {
      receive_id: receiveId,
      msg_type: 'text',
      content: JSON.stringify({ text: content }),
    },
  });
}

/**
 * 发送富文本/卡片消息
 * @param {string} receiveId - 接收者 ID
 * @param {string} content - JSON 字符串格式的消息体
 */
export async function sendInteractiveMessage(receiveId, content) {
  return client.im.message.create({
    params: { receive_id_type: 'chat_id' },
    data: {
      receive_id: receiveId,
      msg_type: 'interactive',
      content,
    },
  });
}

/**
 * 发送图片消息
 * @param {string} receiveId - 接收者 ID
 * @param {string} imageKey - 上传图片后拿到的 image_key
 */
export async function sendImageMessage(receiveId, imageKey) {
  return client.im.message.create({
    params: { receive_id_type: 'chat_id' },
    data: {
      receive_id: receiveId,
      msg_type: 'image',
      content: JSON.stringify({ image_key: imageKey }),
    },
  });
}

/**
 * 发送文件消息
 * @param {string} receiveId - 接收者 ID
 * @param {string} fileKey - 上传文件后拿到的 file_key
 */
export async function sendFileMessage(receiveId, fileKey) {
  return client.im.message.create({
    params: { receive_id_type: 'chat_id' },
    data: {
      receive_id: receiveId,
      msg_type: 'file',
      content: JSON.stringify({ file_key: fileKey }),
    },
  });
}

import fs from 'node:fs';
import path from 'node:path';
import client from './client.js';

/**
 * 上传图片到飞书
 * @param {string} imagePath - 本地图片路径
 * @returns {Promise<string>} image_key
 */
export async function uploadImage(imagePath) {
  const buffer = fs.readFileSync(imagePath);
  const fileName = path.basename(imagePath);

  const res = await client.im.image.create({
    data: { image_type: 'message', image: buffer },
    params: {},
    file: { fieldName: 'image', fileName, data: buffer },
  });

  // 兼容不同版本的 SDK 返回格式
  const imageKey = res?.data?.image_key ?? res?.image_key;
  if (!imageKey) {
    throw new Error(`上传图片失败: ${JSON.stringify(res)}`);
  }
  return imageKey;
}

/**
 * 上传文件到飞书
 * @param {string} filePath - 本地文件路径
 * @returns {Promise<string>} file_key
 */
export async function uploadFile(filePath) {
  const buffer = fs.readFileSync(filePath);
  const ext = path.extname(filePath).toLowerCase();
  const typeMap = {
    '.pdf': 'pdf',
    '.doc': 'doc',
    '.docx': 'doc',
    '.xls': 'xls',
    '.xlsx': 'xls',
    '.ppt': 'ppt',
    '.pptx': 'ppt',
    '.csv': 'csv',
    '.txt': 'stream',
    '.log': 'stream',
  };
  const fileType = typeMap[ext] || 'stream';

  const res = await client.im.file.create({
    data: { file_type: fileType, file_name: path.basename(filePath), file: buffer },
    file: { fieldName: 'file', fileName: path.basename(filePath), data: buffer },
  });

  const fileKey = res?.data?.file_key ?? res?.file_key;
  if (!fileKey) {
    throw new Error(`上传文件失败: ${JSON.stringify(res)}`);
  }
  return fileKey;
}

import client from './client.js';

/**
 * 创建飞书文档
 * @param {string} title - 文档标题
 * @param {string} folderToken - 文件夹 token（可选，创建到知识库的某个文件夹下）
 * @returns {Promise<{documentId: string, url: string}>} 文档 ID 和链接
 */
export async function createDoc(title, folderToken) {
  const res = await client.docx.document.create({
    data: { title, folder_token: folderToken },
  });

  const doc = res?.data?.document;
  if (!doc?.document_id) {
    throw new Error(`创建文档失败: ${JSON.stringify(res)}`);
  }

  return {
    documentId: doc.document_id,
    url: `https://bytedance.feishu.cn/docx/${doc.document_id}`,
  };
}

/**
 * 向飞书文档追加内容块
 * @param {string} documentId - 文档 ID
 * @param {string} blockId - 父级 block ID（文档根节点 ID 即 documentId）
 * @param {Array<object>} blocks - 内容块数组（飞书文档 block 格式）
 * @param {'markdown' | 'block'} format - 内容格式。markdown 会先转为飞书 block
 */
export async function appendDocBlocks(documentId, blockId, blocks) {
  return client.docx.documentBlockChildren.create({
    params: { document_id: documentId, block_id: blockId },
    data: { children: blocks },
  });
}

/**
 * 获取文档根节点信息
 * @param {string} documentId
 * @returns {Promise<object>}
 */
export async function getDocument(documentId) {
  const res = await client.docx.document.get({
    params: { document_id: documentId },
  });
  return res?.data?.document;
}

/**
 * 创建飞书多维表格 (Bitable)
 * @param {string} name - 表格名称
 * @param {string} folderToken - 文件夹 token
 * @returns {Promise<{appToken: string, url: string}>}
 */
export async function createBitable(name, folderToken) {
  const res = await client.bitable.app.create({
    data: { name, folder_token: folderToken },
  });
  const bitable = res?.data?.app;
  if (!bitable?.app_token) {
    throw new Error(`创建多维表格失败: ${JSON.stringify(res)}`);
  }
  return { appToken: bitable.app_token, url: bitable.url };
}

