import fs from 'node:fs';
import path from 'node:path';
import { createDoc, appendDocBlocks } from '../feishu/doc.js';
import { uploadImage, uploadFile } from '../feishu/media.js';
import { sendMessage, sendImageMessage } from '../feishu/message.js';

// 飞书文档 Block 类型定义
const BlockType = {
  Text: (text) => ({ block_type: 2, text }),
  Heading1: (text) => ({ block_type: 3, heading1: text }),
  Heading2: (text) => ({ block_type: 4, heading2: text }),
  Heading3: (text) => ({ block_type: 5, heading3: text }),
  Heading4: (text) => ({ block_type: 6, heading4: text }),
  Heading5: (text) => ({ block_type: 7, heading5: text }),
  Bullet: (text) => ({ block_type: 12, bullet: text }),
  Ordered: (text) => ({ block_type: 13, ordered: text }),
  Code: (text, language = 'Plain Text') => ({
    block_type: 14,
    code: text,
  }),
  Divider: () => ({ block_type: 22, divider: {} }),
  Image: (imageKey) => ({ block_type: 27, image: { token: imageKey } }),
};

/**
 * 文本元素构造器
 * typeId 说明:
 *   1 = 普通文本(textRun), 可带样式
 */
function textRun(content, style) {
  const el = { content, text_element_type: 1, text_run: { content } };
  if (style?.bold) el.text_run.text_element_style = { bold: true };
  if (style?.link) el.text_run.text_element_style = {
    ...(el.text_run.text_element_style || {}),
    link: { url: style.link },
  };
  return el;
}

/**
 * 将 Block 结构体转为包含 elements 属性的飞书文档格式
 * 飞书文档 API 要求每个 block 包含 block_type 和对应的类型字段,
 * 该类型字段的值包含 elements 数组（文本块需要）
 */
function toDocBlock(block) {
  // 找出 block_type 对应的字段名
  const typeMap = {
    2: 'text',
    3: 'heading1',
    4: 'heading2',
    5: 'heading3',
    6: 'heading4',
    7: 'heading5',
    12: 'bullet',
    13: 'ordered',
    14: 'code',
    22: 'divider',
    27: 'image',
  };
  const field = typeMap[block.block_type];
  const value = block[field];

  if (field === 'divider' || field === 'image') {
    return { block_type: block.block_type, [field]: value || {} };
  }

  // 如果是字符串，包成 elements
  let elements;
  if (typeof value === 'string') {
    elements = [textRun(value)];
  } else if (Array.isArray(value)) {
    elements = value;
  } else {
    elements = [];
  }

  return { block_type: block.block_type, [field]: { elements } };
}

// ─── 文档模板 ────────────────────────────────────────────

/**
 * 生成会议纪要模板
 */
function meetingNotes({ title, date, attendees, agenda, notes, actions }) {
  return [
    BlockType.Heading1(`${title || '会议纪要'}`),
    BlockType.Text(`日期：${date || '______'}`),
    BlockType.Text(`参会人：${attendees || '______'}`),
    BlockType.Divider(),
    BlockType.Heading2('会议议程'),
    ...(agenda || ['（待填写）']).map((a) => BlockType.Bullet(a)),
    BlockType.Heading2('会议记录'),
    ...(notes || ['（待填写）']).map((n) => BlockType.Bullet(n)),
    BlockType.Heading2('待办事项'),
    ...(actions || ['（待填写）']).map((a) => BlockType.Bullet(`[ ] ${a}`)),
  ];
}

/**
 * 生成技术文档模板
 */
function techDoc({ title, overview, sections, codeExamples }) {
  const blocks = [
    BlockType.Heading1(title || '技术文档'),
    BlockType.Text(overview || '（概述）'),
    BlockType.Divider(),
  ];

  (sections || []).forEach((sec) => {
    blocks.push(BlockType.Heading2(sec.heading));
    blocks.push(BlockType.Text(sec.content));
  });

  if (codeExamples?.length) {
    blocks.push(BlockType.Heading2('代码示例'));
    codeExamples.forEach((ex) => {
      blocks.push(BlockType.Heading3(ex.title || '示例'));
      blocks.push(BlockType.Code(ex.code, ex.language || 'Plain Text'));
    });
  }

  return blocks;
}

/**
 * 生成项目方案模板
 */
function projectPlan({ title, background, goals, timeline, risks }) {
  return [
    BlockType.Heading1(title || '项目方案'),
    BlockType.Heading2('项目背景'),
    BlockType.Text(background || '（待填写）'),
    BlockType.Heading2('项目目标'),
    ...(goals || ['（待填写）']).map((g) => BlockType.Bullet(g)),
    BlockType.Heading2('时间计划'),
    ...(timeline || ['（待填写）']).map((t) => BlockType.Bullet(t)),
    BlockType.Heading2('风险与应对'),
    ...(risks || ['（待填写）']).map((r) => BlockType.Bullet(r)),
  ];
}

// ─── 模板注册表 ──────────────────────────────────────────

const templates = {
  meeting: meetingNotes,
  tech: techDoc,
  project: projectPlan,
};

/**
 * 生成文档内容并创建飞书文档
 * @param {object} options
 * @param {string} options.template - 模板名称 (meeting | tech | project)
 * @param {string} options.chatId - 飞书群 ID（可选，发通知用）
 * @param {object} options.data - 传给模板的数据
 */
export async function generateDoc({ template, chatId, ...data }) {
  const tplFn = templates[template];
  if (!tplFn) {
    throw new Error(`未知模板 "${template}"，可选: ${Object.keys(templates).join(', ')}`);
  }

  const blocks = tplFn(data);
  const docBlocks = blocks.map(toDocBlock);
  const title = data.title || `${template} - ${new Date().toISOString().slice(0, 10)}`;

  console.log(`正在创建飞书文档: ${title}`);
  const { documentId, url } = await createDoc(title);

  console.log(`正在写入文档内容 (${docBlocks.length} 个块)...`);
  await appendDocBlocks(documentId, documentId, docBlocks);

  console.log(`文档已创建: ${url}`);

  if (chatId) {
    await sendMessage(chatId, `📄 文档已生成\n${title}\n${url}`);
    console.log('已发送通知到群聊');
  }

  return { documentId, url };
}

export { templates };

