import crypto from 'node:crypto';

const APP_SECRET = process.env.FEISHU_APP_SECRET;
const APP_ID = process.env.FEISHU_APP_ID;

// 内存队列（Vercel 冷启动会清空，后面接 KV 存储）
let messageQueue = [];

function verifySignature(timestamp, nonce, body) {
  const raw = [timestamp, nonce, '', APP_SECRET].join('');
  return crypto.createHash('sha256').update(raw).digest('hex');
}

async function getTenantToken() {
  const res = await fetch(
    'https://open.feishu.cn/open-apis/auth/v3/tenant_access_token/internal',
    {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ app_id: APP_ID, app_secret: APP_SECRET }),
    }
  );
  const data = await res.json();
  return data.tenant_access_token;
}

async function sendReply(chatId, text) {
  const token = await getTenantToken();
  return fetch(
    'https://open.feishu.cn/open-apis/im/v1/messages?receive_id_type=chat_id',
    {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${token}`,
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        receive_id: chatId,
        msg_type: 'text',
        content: JSON.stringify({ text }),
      }),
    }
  );
}

export default async function handler(req, res) {
  const body = req.body;

  // URL 验证
  if (body?.type === 'url_verification') {
    console.log('URL verification:', body.challenge);
    return res.json({ challenge: body.challenge });
  }

  // 签名校验
  const timestamp = req.headers['x-lark-request-timestamp'] || '';
  const nonce = req.headers['x-lark-request-nonce'] || '';
  const signature = req.headers['x-lark-signature'] || '';

  if (signature) {
    const expected = verifySignature(timestamp, nonce, JSON.stringify(body));
    if (signature !== expected) {
      return res.status(401).json({ msg: 'invalid signature' });
    }
  }

  // 立即返回 200（飞书要求 3 秒内响应）
  res.json({ code: 0 });

  // 处理消息事件
  const event = body?.event;
  if (!event || event.type !== 'im.message.receive_v1') return;

  const msg = event.message;
  if (!msg || msg.message_type !== 'text') return;

  const chatId = msg.chat_id;
  let text = '';
  try {
    text = JSON.parse(msg.content).text?.trim();
  } catch {
    return;
  }
  if (!text) return;

  console.log(`收到消息: ${text} | chat_id: ${chatId}`);

  // 存入队列，Claude Code 会轮询处理
  messageQueue.push({
    id: Date.now().toString(36) + Math.random().toString(36).slice(2, 8),
    chatId,
    text,
    sender: event.sender?.sender_id?.open_id || 'unknown',
    time: new Date().toISOString(),
  });

  // 只保留最近 50 条
  if (messageQueue.length > 50) {
    messageQueue = messageQueue.slice(-50);
  }
}

// ─── 轮询接口：Claude Code 取消息 ────────────────────────

export async function pollHandler(req, res) {
  const messages = [...messageQueue];
  messageQueue = [];
  return res.json({ messages, count: messages.length });
}

// 路由分发
export const config = { api: { bodyParser: true } };

