import 'dotenv/config';
import express from 'express';
import crypto from 'node:crypto';
import { sendMessage } from './feishu/message.js';
import { generateDoc } from './commands/doc.js';
import { generateDiagram } from './commands/diagram.js';

const app = express();
app.use(express.json());

const PORT = process.env.PORT || 3000;
const APP_SECRET = process.env.FEISHU_APP_SECRET;

// ─── 签名验证 ────────────────────────────────────────────

function verifySignature(timestamp, nonce, body) {
  const raw = [timestamp, nonce, '', APP_SECRET].join('');
  const sign = crypto.createHash('sha256').update(raw).digest('hex');
  return sign;
}

// ─── 飞书事件回调 ────────────────────────────────────────

app.post('/feishu/event', (req, res) => {
  const body = req.body;
  const headers = req.headers;

  // 1. URL 验证：飞书首次配置回调地址时发送 challenge
  if (body.type === 'url_verification') {
    console.log('收到 URL 验证:', body.challenge);
    return res.json({ challenge: body.challenge });
  }

  // 2. 签名校验
  const timestamp = headers['x-lark-request-timestamp'] || '';
  const nonce = headers['x-lark-request-nonce'] || '';
  const signature = headers['x-lark-signature'] || '';

  const expectedSign = verifySignature(timestamp, nonce, JSON.stringify(body));
  if (signature && signature !== expectedSign) {
    console.warn('签名校验失败');
    return res.status(401).json({ msg: 'invalid signature' });
  }

  // 3. 处理事件
  const event = body.event;
  if (!event) {
    return res.json({ code: 0 });
  }

  // 飞书要求先返回 200，再异步处理
  res.json({ code: 0 });

  handleEvent(event).catch((err) => {
    console.error('事件处理异常:', err);
  });
});

// ─── 事件处理 ────────────────────────────────────────────

async function handleEvent(event) {
  // 只处理用户发来的消息
  if (event.type !== 'im.message.receive_v1') return;

  const msg = event.message;
  if (!msg || msg.message_type !== 'text') return;

  // 只处理群聊消息
  const chatId = msg.chat_id;
  const content = JSON.parse(msg.content);
  const text = content.text?.trim();

  if (!text) return;

  console.log(`收到消息: ${text}  (chat_id: ${chatId})`);

  // 解析命令: /doc 或 /diagram
  if (text.startsWith('/doc')) {
    await handleDocCommand(chatId, text);
  } else if (text.startsWith('/diagram')) {
    await handleDiagramCommand(chatId, text);
  } else if (text.startsWith('/help') || text === '帮助') {
    await sendMessage(chatId, `支持的命令：
/doc meeting 标题 — 生成会议纪要
/doc tech 标题 — 生成技术文档
/doc project 标题 — 生成项目方案
/diagram flowchart 标题 — 流程图
/diagram sequence 标题 — 时序图
/diagram gantt 标题 — 甘特图
/diagram pie 标题 — 饼图

发送 /help 查看帮助`);
  } else {
    await sendMessage(chatId, `收到消息：${text}\n发送 /help 查看可用命令`);
  }
}

// ─── 命令处理 ────────────────────────────────────────────

async function handleDocCommand(chatId, text) {
  // 格式: /doc meeting 标题
  const parts = text.replace('/doc', '').trim().split(/\s+/);
  const template = parts[0];
  const title = parts.slice(1).join(' ') || '未命名文档';

  if (!['meeting', 'tech', 'project'].includes(template)) {
    return sendMessage(chatId, `未知文档模板「${template}」，可选: meeting / tech / project`);
  }

  try {
    await sendMessage(chatId, `正在生成文档「${title}」...`);
    const result = await generateDoc({ template, title, chatId });
  } catch (err) {
    await sendMessage(chatId, `生成文档失败: ${err.message}`);
  }
}

async function handleDiagramCommand(chatId, text) {
  // 格式: /diagram flowchart 标题
  const parts = text.replace('/diagram', '').trim().split(/\s+/);
  const type = parts[0];
  const title = parts.slice(1).join(' ') || '';

  const validTypes = ['flowchart', 'sequence', 'classDiagram', 'gantt', 'pie', 'er'];
  if (!validTypes.includes(type)) {
    return sendMessage(chatId, `未知图表类型「${type}」，可选: ${validTypes.join(' / ')}`);
  }

  try {
    await sendMessage(chatId, `正在生成「${title || type}」图表...`);
    const result = await generateDiagram({ type, title, chatId, toDoc: true });
  } catch (err) {
    await sendMessage(chatId, `生成图表失败: ${err.message}`);
  }
}

// ─── 启动 ────────────────────────────────────────────────

app.listen(PORT, () => {
  console.log(`飞书机器人服务已启动: http://localhost:${PORT}`);
  console.log(`事件回调地址: http://localhost:${PORT}/feishu/event`);
});

