    'https://open.feishu.cn/open-apis/auth/v3/tenant_access_token/internal',
    {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ app_id: APP_ID, app_secret: APP_SECRET }),
    }
  );
  return (await res.json()).tenant_access_token;
}

async function sendFeishuMsg(token, chatId, text) {
  const res = await fetch(
    'https://open.feishu.cn/open-apis/im/v1/messages?receive_id_type=chat_id',
    {
      method: 'POST',
      headers: {
        Authorization: `Bearer ${token}`,
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        receive_id: chatId,
        msg_type: 'text',
        content: JSON.stringify({ text }),
      }),
    }
  );
  return res.json();
}

async function createFeishuDoc(token, title) {
  const res = await fetch(
    'https://open.feishu.cn/open-apis/docx/v1/documents',
    {
      method: 'POST',
      headers: {
        Authorization: `Bearer ${token}`,
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({ title }),
    }
  );
  const data = await res.json();
  const docId = data?.data?.document?.document_id;
  return { documentId: docId, url: `https://bytedance.feishu.cn/docx/${docId}` };
}

async function appendDocBlocks(token, docId, blockId, blocks) {
  return fetch(
    `https://open.feishu.cn/open-apis/docx/v1/documents/${docId}/blocks/${blockId}/children`,
    {
      method: 'POST',
      headers: {
        Authorization: `Bearer ${token}`,
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({ children: blocks }),
    }
  );
}

async function uploadImageToFeishu(token, imageBuffer) {
  const formData = new FormData();
  formData.append('image_type', 'message');
  formData.append('image', new Blob([imageBuffer]), 'image.png');

  const res = await fetch('https://open.feishu.cn/open-apis/im/v1/images', {
    method: 'POST',
    headers: { Authorization: `Bearer ${token}` },
    body: formData,
  });
  const data = await res.json();
  return data?.data?.image_key;
}

// ─── 签名校验 ──────────────────────────────────────────────

function verifySignature(timestamp, nonce, body) {
  const raw = [timestamp, nonce, '', APP_SECRET].join('');
  return crypto.createHash('sha256').update(raw).digest('hex');
}

// ─── 中间件：鉴权（保护内部 API）────────────────────────────

function auth(req, res, next) {
  const provided = req.headers['x-secret'] || req.query.secret;
  if (provided !== SECRET) {
    return res.status(403).json({ error: 'unauthorized' });
  }
  next();
}

// ─── 飞书事件回调 ──────────────────────────────────────────

app.post('/feishu/event', (req, res) => {
  const body = req.body;

  // URL 验证
  if (body?.type === 'url_verification') {
    console.log('URL verification OK');
    return res.json({ challenge: body.challenge });
  }

  // 签名校验
  const timestamp = req.headers['x-lark-request-timestamp'] || '';
  const nonce = req.headers['x-lark-request-nonce'] || '';
  const signature = req.headers['x-lark-signature'] || '';

  if (signature) {
    const expected = verifySignature(timestamp, nonce, JSON.stringify(body));
    if (signature !== expected) {
      return res.status(401).json({ msg: 'invalid signature' });
    }
  }

  // 立即返回 200
  res.json({ code: 0 });

  // 处理消息
  const event = body?.event;
  if (!event || event.type !== 'im.message.receive_v1') return;

  const msg = event.message;
  if (!msg || msg.message_type !== 'text') return;

  let text = '';
  try { text = JSON.parse(msg.content).text?.trim(); } catch { return; }
  if (!text) return;

  console.log(`[飞书消息] ${text} | chat: ${msg.chat_id}`);

  messageQueue.push({
    id: Date.now().toString(36) + Math.random().toString(36).slice(2, 8),
    chatId: msg.chat_id,
    text,
    time: new Date().toISOString(),
  });

  if (messageQueue.length > 100) messageQueue = messageQueue.slice(-100);
});

// ─── Claude Code 接口 ──────────────────────────────────────

// 拉取消息（Claude Code 轮询这个接口）
app.get('/queue', auth, (req, res) => {
  const msgs = [...messageQueue];
  messageQueue = [];
  res.json({ messages: msgs });
});

// 发消息到飞书群
app.post('/send', auth, async (req, res) => {
  const { chatId, text } = req.body;
  if (!chatId || !text) return res.status(400).json({ error: 'chatId and text required' });
  try {
    const token = await getToken();
    const result = await sendFeishuMsg(token, chatId, text);
    res.json(result);
  } catch (e) {
    res.status(500).json({ error: e.message });
  }
});

// 创建飞书文档
app.post('/doc/create', auth, async (req, res) => {
  const { title, blocks, chatId } = req.body;
  if (!title) return res.status(400).json({ error: 'title required' });
  try {
    const token = await getToken();
    const doc = await createFeishuDoc(token, title);
    if (blocks?.length) {
      await appendDocBlocks(token, doc.documentId, doc.documentId, blocks);
    }
    if (chatId) {
      await sendFeishuMsg(token, chatId, `文档已生成: ${doc.url}`);
    }
    res.json(doc);
  } catch (e) {
    res.status(500).json({ error: e.message });
  }
});

// 生成 Mermaid 图表并上传
app.post('/diagram/create', auth, async (req, res) => {
  const { mermaid, title, chatId } = req.body;
  if (!mermaid) return res.status(400).json({ error: 'mermaid code required' });
  try {
    const token = await getToken();
    // 调用 mermaid.ink 渲染
    const encoded = Buffer.from(mermaid).toString('base64');
    const imgRes = await fetch(`https://mermaid.ink/img/${encoded}?type=png`);
    if (!imgRes.ok) throw new Error(`Mermaid render failed: ${imgRes.status}`);
    const imgBuf = Buffer.from(await imgRes.arrayBuffer());
    const imageKey = await uploadImageToFeishu(token, imgBuf);

    // 发到群
    if (chatId) {
      await fetch(
        `https://open.feishu.cn/open-apis/im/v1/messages?receive_id_type=chat_id`,
        {
          method: 'POST',
          headers: {
            Authorization: `Bearer ${token}`,
            'Content-Type': 'application/json',
          },
          body: JSON.stringify({
            receive_id: chatId,
            msg_type: 'image',
            content: JSON.stringify({ image_key: imageKey }),
          }),
        }
      );
    }

    // 创建文档
    let docUrl;
    if (title) {
      const doc = await createFeishuDoc(token, title);
      await appendDocBlocks(token, doc.documentId, doc.documentId, [
        {
          block_type: 27,
          image: { token: imageKey },
        },
      ]);
      docUrl = doc.url;
    }

    res.json({ imageKey, docUrl });
  } catch (e) {
    res.status(500).json({ error: e.message });
  }
});

// ─── 启动 ──────────────────────────────────────────────────

app.listen(PORT, () => {
  console.log(`飞书机器人桥接服务已启动: http://localhost:${PORT}`);
  console.log(`事件回调: /feishu/event`);
  console.log(`消息队列: /queue`);
  console.log(`发送消息: /send`);
  console.log(`创建文档: /doc/create`);
  console.log(`创建图表: /diagram/create`);
});

