    if text in ["你好", "hello", "hi", "在吗"]:
        return "你好！我是 Claude 助手机器人。\n\n支持的功能：\n• 聊天问答\n• 写文档（输入你要的文档主题）\n• 画图表（输入你要的图表描述）\n\n直接发消息给我即可！"

    if text == "帮助" or text == "help":
        return """Claude 飞书助手支持：

📄 写文档 — 直接告诉我要写什么
📊 画图表 — 描述你要的图表类型
💬 聊天问答 — 随便聊

示例：
  "帮我写一份项目周报"
  "画一个用户登录流程图"
  "这个技术方案有什么问题？"

直接 @机器人 发消息即可！"""

    # 默认：传给 Claude Code 处理（通过轮询机制）
    return None


def main():
    print("飞书消息轮询已启动 (间隔 5 秒)")
    print(f"群聊: {CHAT_ID}")
    print()

    last_id = get_last_id()

    while True:
        try:
            token = get_token()
            msgs = list_messages(token)

            if not msgs:
                time.sleep(5)
                continue

            new_msgs = []
            for msg in msgs:
                msg_id = msg.get("message_id", "")
                if msg_id == last_id:
                    break
                new_msgs.append(msg)

            if new_msgs:
                # 倒序处理（从旧到新）
                for msg in reversed(new_msgs):
                    text = get_text(msg)
                    if not text:
                        continue

                    reply = process_message(msg, token)
                    if reply:
                        print(f"[回复] {text[:50]} → {reply[:50]}...")
                        send_message(token, reply)
                        time.sleep(0.5)

                save_last_id(new_msgs[0].get("message_id", ""))

            time.sleep(5)

        except KeyboardInterrupt:
            print("\n已停止")
            break
        except Exception as e:
            print(f"错误: {e}")
            time.sleep(10)


if __name__ == "__main__":
    main()

